bin/sh: 3: : not found # /bin/ls user.txt # head user^H^H^H^H^H^H^H^H^H^H^H /bin/sh: 5: head: not found # cd /root # /bin/ls reports root.txt # cat^H /bin/sh: 8: ca: not found # head root.txt /bin/sh: 9: head: not found # /bin/cat root.txt af13b0bee69f8a877c3faf667f7beacf #
